      <div class="field-group"><label>Austenitise (kWh/kg) <span title="Furnace heat per kg of blank to ~900°C incl. losses. Default 0.30.">ℹ</span></label><input type="number" id="sm-hs-energy" step="0.05" min="0" value="0.30"/></div>
